// frontend/src/lib/communityApi.js
const BASE = process.env.REACT_APP_API_BASE || "http://127.0.0.1:8000";

async function req(path, { method = "GET", body } = {}) {
  const res = await fetch(`${BASE}${path}`, {
    method,
    headers: { "Content-Type": "application/json" },
    body: body ? JSON.stringify(body) : undefined,
  });
  if (!res.ok) {
    const text = await res.text().catch(() => "");
    throw new Error(`HTTP ${res.status} ${res.statusText}: ${text || path}`);
  }
  return res.json();
}

/** Backed by your FastAPI community routes (adjust paths if needed). */
export function fetchFeed({ city = "", limit = 20, cursor = "" } = {}) {
  const q = new URLSearchParams();
  if (city) q.set("city", city);
  if (limit) q.set("limit", String(limit));
  if (cursor) q.set("cursor", cursor);
  return req(`/api/community/feed?${q.toString()}`);
}

export function createQuestion({ city = "", text = "" }) {
  return req(`/api/community/questions`, {
    method: "POST",
    body: { city, text },
  });
}

export function replyToQuestion({ questionId, text }) {
  return req(`/api/community/questions/${encodeURIComponent(questionId)}/replies`, {
    method: "POST",
    body: { text },
  });
}

/** Generic vote. type: "question" | "reply"; delta: +1 (like) or -1 (unlike) */
export function vote({ type = "question", id, delta = 1 }) {
  return req(`/api/community/vote`, {
    method: "POST",
    body: { type, id, delta },
  });
}

/** Optional: report content */
export function report({ type = "question", id, reason = "" }) {
  return req(`/api/community/report`, {
    method: "POST",
    body: { type, id, reason },
  });
}

/* ---- Aliases expected by Community.jsx ----
   - api.list(...)    -> fetchFeed(...)
   - api.create(...)  -> createQuestion(...)
   - api.like(...)    -> vote({ type, id, delta: +1 })
   - api.repost(...)  -> tries POST /api/community/repost (adjust if you don’t have it)
   - api.reply(...)   -> replyToQuestion(...)
*/
function list(args) {
  return fetchFeed(args);
}

function create(args) {
  // expects { city, text }
  return createQuestion(args);
}

function like({ id, type = "question" }) {
  return vote({ id, type, delta: 1 });
}

// If your backend doesn’t implement repost, either add that route
// or change Community.jsx to hide the action. This implementation
// will 404 if the route doesn’t exist.
async function repost({ id }) {
  return req(`/api/community/repost`, {
    method: "POST",
    body: { id },
  });
}

function reply({ questionId, text }) {
  return replyToQuestion({ questionId, text });
}

// Named exports (for direct imports) + default bundle (for `import api from ...`)
const api = {
  fetchFeed,
  createQuestion,
  replyToQuestion,
  vote,
  report,
  // aliases:
  list,
  create,
  like,
  repost,
  reply,
};

export default api;
